48	export const RecordTableCellBaseContainer = ({
49	  children,
50	}: {
51	  children: ReactNode;
52	}) => {
53	  const {
54	    isRecordFieldReadOnly: isReadOnly,
55	    fieldDefinition,
56	    isLabelIdentifier,
57	  } = useContext(FieldContext);
58	  const { openTableCell } = useOpenRecordTableCellFromCell();
59	  const { theme } = useContext(ThemeContext);
60	
61	  const { cellPosition } = useContext(RecordTableCellContext);
62	  const { recordTableId } = useRecordTableContextOrThrow();
63	
64	  const isChipDisplay = isFieldIdentifierDisplay(
65	    fieldDefinition,
66	    isLabelIdentifier,
67	  );
68	
69	  const handleContainerClick = () => {
70	    openTableCell();
71	  };
72	
73	  return (
74	    <StyledBaseContainer
75	      onClick={handleContainerClick}
76	      backgroundColorSecondary={theme.background.secondary}
77	      fontColorSecondary={theme.font.color.secondary}
78	      fontColorMedium={theme.border.color.medium}
79	      isReadOnly={isReadOnly ?? false}
80	      id={getRecordTableCellId(
81	        recordTableId,
82	        cellPosition.column,
83	        cellPosition.row,
84	      )}
85	      data-record-table-col={cellPosition.column}
86	      data-record-table-row={cellPosition.row}
87	      data-click-outside-id={
88	        isChipDisplay ? RECORD_CHIP_CLICK_OUTSIDE_ID : undefined
89	      }
90	    >
91	      {children}
92	    </StyledBaseContainer>
93	  );
94	};
