1	import { useObjectMetadataItem } from '@/object-metadata/hooks/useObjectMetadataItem';
2	import { formatFieldMetadataItemAsColumnDefinition } from '@/object-metadata/utils/formatFieldMetadataItemAsColumnDefinition';
3	import { useUpdateOneRecord } from '@/object-record/hooks/useUpdateOneRecord';
4	import { useIsRecordFieldReadOnly } from '@/object-record/read-only/hooks/useIsRecordFieldReadOnly';
5	import {
6	  FieldContext,
7	  type RecordUpdateHook,
8	  type RecordUpdateHookParams,
9	} from '@/object-record/record-field/ui/contexts/FieldContext';
10	import { type ReactNode } from 'react';
