12	export const FieldContextProvider = ({
13	  clearable,
14	  fieldMetadataName,
15	  fieldPosition,
16	  isLabelIdentifier = false,
17	  objectNameSingular,
18	  objectRecordId,
19	  customUseUpdateOneObjectHook,
20	  overridenIsFieldEmpty,
21	  onMouseEnter,
22	  anchorId,
23	  children,
24	}: {
25	  clearable?: boolean;
26	  fieldMetadataName: string;
27	  fieldPosition: number;
28	  isLabelIdentifier?: boolean;
29	  objectNameSingular: string;
30	  objectRecordId: string;
31	  customUseUpdateOneObjectHook?: RecordUpdateHook;
32	  overridenIsFieldEmpty?: boolean;
33	  onMouseEnter?: () => void;
34	  anchorId?: string;
35	  children: ReactNode;
36	}) => {
37	  const { objectMetadataItem } = useObjectMetadataItem({
38	    objectNameSingular,
39	  });
40	
41	  const fieldMetadataItem = objectMetadataItem?.fields.find(
42	    (field) => field.name === fieldMetadataName,
43	  );
44	
45	  const { updateOneRecord } = useUpdateOneRecord();
46	
47	  const useUpdateOneObjectMutation: RecordUpdateHook = () => {
48	    const updateEntity = ({ variables }: RecordUpdateHookParams) => {
49	      updateOneRecord({
50	        objectNameSingular,
51	        idToUpdate: variables.where.id as string,
52	        updateOneRecordInput: variables.updateOneRecordInput,
53	      });
54	    };
55	
56	    return [updateEntity, { loading: false }];
57	  };
58	
59	  const isRecordFieldReadOnly = useIsRecordFieldReadOnly({
60	    recordId: objectRecordId,
61	    fieldMetadataId: fieldMetadataItem?.id ?? '',
62	    objectMetadataId: objectMetadataItem.id,
63	  });
64	
65	  if (!fieldMetadataItem) {
66	    return null;
67	  }
68	
69	  return (
70	    <FieldContext.Provider
71	      key={objectRecordId + fieldMetadataItem.id}
72	      value={{
73	        recordId: objectRecordId,
74	        isLabelIdentifier,
75	        fieldDefinition: formatFieldMetadataItemAsColumnDefinition({
76	          field: fieldMetadataItem,
77	          showLabel: true,
78	          position: fieldPosition,
79	          objectMetadataItem,
80	          labelWidth: 90,
81	        }),
82	        useUpdateRecord:
83	          customUseUpdateOneObjectHook ?? useUpdateOneObjectMutation,
84	        clearable,
85	        overridenIsFieldEmpty,
86	        isRecordFieldReadOnly,
87	        onMouseEnter,
88	        anchorId,
89	      }}
90	    >
91	      {children}
92	    </FieldContext.Provider>
93	  );
94	};
