1	import { useObjectMetadataItemById } from '@/object-metadata/hooks/useObjectMetadataItemById';
2	import { formatFieldMetadataItemAsFieldDefinition } from '@/object-metadata/utils/formatFieldMetadataItemAsFieldDefinition';
3	import { getObjectPermissionsForObject } from '@/object-metadata/utils/getObjectPermissionsForObject';
4	import { useObjectPermissions } from '@/object-record/hooks/useObjectPermissions';
5	import { useIsRecordReadOnly } from '@/object-record/read-only/hooks/useIsRecordReadOnly';
6	import { isRecordFieldReadOnly } from '@/object-record/read-only/utils/isRecordFieldReadOnly';
