8	export type UseFieldIsReadOnlyParams = {
9	  fieldMetadataId: string;
10	  objectMetadataId: string;
11	  recordId: string;
12	};
13	
14	export const useIsRecordFieldReadOnly = ({
15	  fieldMetadataId,
16	  objectMetadataId,
17	  recordId,
18	}: UseFieldIsReadOnlyParams) => {
19	  const { objectMetadataItem } = useObjectMetadataItemById({
20	    objectId: objectMetadataId,
21	  });
22	
23	  const fieldMetadataItem = objectMetadataItem.fields.find(
24	    (field) => field.id === fieldMetadataId,
25	  );
26	
27	  const { objectPermissionsByObjectMetadataId } = useObjectPermissions();
28	
29	  const objectPermissions = getObjectPermissionsForObject(
30	    objectPermissionsByObjectMetadataId,
31	    objectMetadataId,
32	  );
33	
34	  const isRecordReadOnly = useIsRecordReadOnly({
35	    recordId,
36	    objectMetadataId,
37	  });
38	
39	  if (!fieldMetadataItem) {
40	    return false;
41	  }
42	
43	  const fieldDefinition = formatFieldMetadataItemAsFieldDefinition({
44	    field: fieldMetadataItem,
45	    objectMetadataItem,
46	  });
47	
48	  return isRecordFieldReadOnly({
49	    isRecordReadOnly,
50	    isSystemObject: objectMetadataItem.isSystem,
51	    objectPermissions,
52	    fieldMetadataItem,
53	    fieldDefinition,
54	    objectPermissionsByObjectMetadataId,
55	  });
56	};
