1	import { type FieldMetadataItem } from '@/object-metadata/types/FieldMetadataItem';
2	import { isFieldMetadataReadOnlyByPermissions } from '@/object-record/read-only/utils/internal/isFieldMetadataReadOnlyByPermissions';
3	import { isOneToManyRelationFieldReadOnlyDueToTargetUpdatePermission } from '@/object-record/read-only/utils/isOneToManyRelationFieldReadOnlyDueToTargetUpdatePermission';
4	import { type FieldDefinition } from '@/object-record/record-field/ui/types/FieldDefinition';
5	import { type FieldMetadata } from '@/object-record/record-field/ui/types/FieldMetadata';
6	import { type ObjectPermission } from '~/generated-metadata/graphql';
7	import { type ObjectPermissions } from 'twenty-shared/types';
8	import { isDefined } from 'twenty-shared/utils';
9	
10	type ObjectPermissionsByObjectMetadataId = Record<
11	  string,
12	  ObjectPermissions & { objectMetadataId: string }
13	>;
14	
15	type IsRecordFieldReadOnlyParams = {
16	  isRecordReadOnly: boolean;
17	  isSystemObject?: boolean;
18	  fieldMetadataItem: Pick<
19	    FieldMetadataItem,
20	    'id' | 'isUIReadOnly' | 'isCustom'
21	  >;
22	  objectPermissions: ObjectPermission;
23	  fieldDefinition?: FieldDefinition<FieldMetadata>;
24	  objectPermissionsByObjectMetadataId?: ObjectPermissionsByObjectMetadataId;
25	};
26	
27	export const isRecordFieldReadOnly = ({
28	  objectPermissions,
29	  isRecordReadOnly,
30	  isSystemObject,
31	  fieldMetadataItem,
32	  fieldDefinition,
33	  objectPermissionsByObjectMetadataId,
34	}: IsRecordFieldReadOnlyParams) => {
35	  const fieldReadOnlyByPermissions = isFieldMetadataReadOnlyByPermissions({
36	    objectPermissions,
37	    fieldMetadataId: fieldMetadataItem.id,
38	  });
39	
40	  const oneToManyTargetReadOnly =
41	    isDefined(fieldDefinition) &&
42	    isDefined(objectPermissionsByObjectMetadataId) &&
43	    isOneToManyRelationFieldReadOnlyDueToTargetUpdatePermission({
44	      fieldDefinition,
45	      objectPermissionsByObjectMetadataId,
46	    });
47	
48	  return (
49	    isRecordReadOnly ||
50	    (isSystemObject === true && fieldMetadataItem.isCustom !== true) ||
51	    fieldMetadataItem.isUIReadOnly ||
52	    fieldReadOnlyByPermissions ||
53	    oneToManyTargetReadOnly
54	  );
55	};
