14	export const useIsRecordReadOnly = ({
15	  recordId,
16	  objectMetadataId,
17	}: UseIsRecordReadOnlyParams) => {
18	  const isLayoutCustomizationModeEnabled = useAtomStateValue(
19	    isLayoutCustomizationModeEnabledState,
20	  );
21	
22	  const { objectMetadataItem } = useObjectMetadataItemById({
23	    objectId: objectMetadataId,
24	  });
25	
26	  const { objectPermissionsByObjectMetadataId } = useObjectPermissions();
27	
