export const isRecordFieldReadOnly = ({
  isRecordReadOnly,
  isSystemObject,
  fieldMetadataItem,
  objectPermissions,
  fieldDefinition,
  objectPermissionsByObjectMetadataId,
}) => {
  return (
    isRecordReadOnly ||  // Entire record is read-only
    (isSystemObject === true && fieldMetadataItem.isCustom !== true) ||  // System field
    fieldMetadataItem.isUIReadOnly ||  // Field explicitly marked read-only
    fieldReadOnlyByPermissions ||  // User doesn't have write permission
    oneToManyTargetReadOnly  // Related object lacks update permission
  );
};
```

